import { Link, useNavigate } from "react-router-dom";

const Navbar = () => {
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user"));

  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    navigate("/login");
  };

  return (
    <nav className="bg-white shadow px-6 py-4 flex justify-between items-center">
      <Link to={user ? (user.role === "admin" ? "/admin" : "/home") : "/login"} className="font-bold text-xl">
        EventHub
      </Link>

      {user ? (
        <div className="flex items-center gap-4">
          <span className="font-medium">{user.name}</span>
          <button onClick={handleLogout} className="bg-red-600 text-white px-3 py-1 rounded">Logout</button>
        </div>
      ) : (
        <div>
          <Link to="/login" className="px-3 py-1 text-purple-600 font-semibold">Login</Link>
          <Link to="/register" className="px-3 py-1 text-purple-600 font-semibold">Register</Link>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
